+class CoreTelemetryMapper {
+  static CoreTelemetryData fromJson(Map<String, dynamic> json) {
+    try {
+      return CoreTelemetryData(
+        connected: json['connected'] as bool? ?? false,
+        status: VfdStatusExtension.fromString(
+          json['status'] as String? ?? 'disconnected',
+        ),
+        direction: VfdDirectionExtension.fromJson(json['direction'] as String?),
+        targetFrequency: _safeDouble(json['target_frequency_hz'], 0.0),
+        frequency: _safeDouble(json['frequency_hz'], 0.0),
+        timestamp: DateTime.now(),
+      );
+    } catch (e) {
+      throw ApiException.badRequest(
+        'Invalid core telemetry data: $e',
+        endpoint: '/api/vfd/core',
+      );
+    }
+  }
+
+  static double _safeDouble(dynamic value, double defaultValue) {
+    if (value == null) return defaultValue;
+    if (value is num) return value.toDouble();
+    if (value is String) {
+      final parsed = double.tryParse(value);
+      return parsed ?? defaultValue;
+    }
+    return defaultValue;
+  }
+}

