+  final VfdStatus status;
+  final VfdDirection? direction;
+  final double targetFrequency;
+  final double frequency;
+  final DateTime timestamp;
+
+  const CoreTelemetryData({
+    required this.connected,
+    required this.status,
+    this.direction,
+    required this.targetFrequency,
+    required this.frequency,
+    required this.timestamp,
+  });
+
+  bool get isRunning => status == VfdStatus.running;
+  bool get isFault => status == VfdStatus.fault;
+  bool get isDisconnected => status == VfdStatus.disconnected || !connected;
+  bool get isIdle => status == VfdStatus.idle;
+
+  String get frequencyFormatted => '${frequency.toStringAsFixed(1)} Hz';
+  String get targetFrequencyFormatted => '${targetFrequency.toStringAsFixed(1)} Hz';
+
+  @override
+  String toString() =>
+      'CoreTelemetryData(status: $status, frequency: $frequencyFormatted, target: $targetFrequencyFormatted)';
